  "presets": [
    "next/babel"
  ],
  "plugins": [
    [
      "babel-plugin-styled-components", // <- you must: npm install -D babel-plugin-styled-components
      {
        "ssr": true,
        "minify": true,
        "transpileTemplateLiterals": true,
        "pure": true,
        "displayName": true,
        "preprocess": false
      }
    ]
  ]
}
```
