I had the same problem with [**material-ui**](https://github.com/mui-org/material-ui) & Next.js.
This is the component I created, I wrapped components that need to be rendering on the client side.
```jsx
import React from "react";

const ClientOnly = ({ children, ...delegated }) => {

  const [hasMounted, setHasMounted] = React.useState(false);

  React.useEffect(() => {
    setHasMounted(true);
  }, []);

  if (!hasMounted) return null

  return (
    <React.Fragment {...delegated}>
      {children}
    </React.Fragment>
  );
}

export default ClientOnly
```

